import{_ as e}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o as l,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"تنظیمات پروژه (Project Settings)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/configuration/project-settings.md","filePath":"fa/configuration/project-settings.md"}'),r={name:"fa/configuration/project-settings.md"};function n(s,t,i,c,g,h){return l(),o("div",null,[...t[0]||(t[0]=[d('<div dir="rtl"><h1 id="تنظیمات-پروژه-project-settings" tabindex="-1"><i class="ph-fill ph-gear-six"></i> تنظیمات پروژه (Project Settings) <a class="header-anchor" href="#تنظیمات-پروژه-project-settings" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; تنظیمات پروژه (Project Settings)&quot;">​</a></h1><p>تمام تنظیمات عمومی WebAP در یک مکان واحد متمرکز شده‌اند: <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+e+'" alt=""></p><h2 id="تنظیمات-عمومی-general-settings" tabindex="-1">تنظیمات عمومی (General Settings) <a class="header-anchor" href="#تنظیمات-عمومی-general-settings" aria-label="Permalink to &quot;تنظیمات عمومی (General Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">پارامتر</th><th style="text-align:left;">توضیحات</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">خط پایه عملکرد. • اگر FPS فعلی به زیر این مقدار سقوط کند (با در نظر گرفتن حاشیه عملکرد)، افزونه شروع به کاهش کیفیت گرافیک می‌کند. • اگر FPS به‌طور پیوسته بالای آن باقی بماند، افزونه تلاش می‌کند تا کیفیت را بهبود بخشد. <em>توصیه:</em> یک مقدار منطقی تعیین کنید. برای WebGL مقدار استاندارد عملی <code>60</code> است، اما برای پروژه‌های سه‌بعدی سنگین می‌توانید از <code>30</code> استفاده کنید.</td></tr></tbody></table><h2 id="تنظیمات-ایندکسر-indexer-settings" tabindex="-1">تنظیمات ایندکسر (Indexer Settings) <a class="header-anchor" href="#تنظیمات-ایندکسر-indexer-settings" aria-label="Permalink to &quot;تنظیمات ایندکسر (Indexer Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">پارامتر</th><th style="text-align:left;">توضیحات</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">مدت زمانی (به ثانیه) که سیستم پس از <em>کاهش</em> کیفیت صبر می‌کند تا FPS را دوباره ارزیابی کند. <em>توصیه:</em> باید کوتاه باشد (<code>1.0</code> - <code>2.0</code> ثانیه). سیستم باید به سرعت به تأخیرها پاسخ دهد و بار اضافی را کم کند تا زمانی که FPS تثبیت شود.</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">زمان انتظار پس از <em>افزایش</em> کیفیت. <em>توصیه:</em> باید طولانی باشد (<code>5.0</code> - <code>10.0</code> ثانیه). قبل از اینکه سیستم دوباره تحت فشار قرار گیرد، باید تأیید کند که بهبود گرافیک قبلی ثبات فریم را از بین نبرده است.</td></tr></tbody></table><h2 id="سیستم-جریمه-ضد-یویو-anti-yo-yo-penalty-system" tabindex="-1">سیستم جریمه ضد یویو (Anti Yo-Yo Penalty System) <a class="header-anchor" href="#سیستم-جریمه-ضد-یویو-anti-yo-yo-penalty-system" aria-label="Permalink to &quot;سیستم جریمه ضد یویو (Anti Yo-Yo Penalty System)&quot;">​</a></h2><p>از &quot;اثر یویو&quot; جلوگیری می‌کند، جایی که کیفیت به‌طور بی‌پایانی بین دو سطح نوسان می‌کند.</p><table tabindex="0"><thead><tr><th style="text-align:left;">پارامتر</th><th style="text-align:left;">توضیحات</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">بازه زمانی پس از <em>افزایش</em> کیفیت که در طی آن سیستم به دقت FPS را نظارت می‌کند. اگر در این دوره افت FPS رخ دهد، سیستم آن را به‌عنوان اثر یویو طبقه‌بندی می‌کند.</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">مدت زمان جریمه (مثلاً <code>60</code> ثانیه) که در طول آن هرگونه تلاش برای <em>افزایش</em> کیفیت به‌طور قطعی مسدود می‌شود.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">یادداشت</p><p>این جریمه صرفاً افزایش‌ها را مسدود می‌کند. اگر FPS دوباره افت کند، سیستم هنوز هم می‌تواند در مواقع اضطراری کیفیت را کاهش دهد.</p></div><h2 id="مقیاس‌کننده‌ها-scalers" tabindex="-1">مقیاس‌کننده‌ها (Scalers) <a class="header-anchor" href="#مقیاس‌کننده‌ها-scalers" aria-label="Permalink to &quot;مقیاس‌کننده‌ها (Scalers)&quot;">​</a></h2><p>هر Scaler فعال مجموعه‌ای از پارامترهای پایه دارد. این پارامترها &quot;هزینه&quot; آن را برای سیستم تعیین می‌کنند. افزونه به‌طور خودکار این هزینه را در لحظه محاسبه می‌کند: Scaler با کمترین تأثیر بصری و متناسب با هدف فعلی (Target - CPU/GPU) در اولویت اجرا قرار می‌گیرد.</p><table tabindex="0"><thead><tr><th style="text-align:left;">پارامتر</th><th style="text-align:left;">توضیحات</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">تعداد گام‌های (سطوح) مجزا بین کیفیت پایه و حداقل. به‌عنوان مثال، <code>Max Level = 4</code> یعنی این Scaler دارای ۴ مرحله کاهش کیفیت است.</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">حداقل مقدار مقیاس (که وقتی Scaler به <code>Max Level</code> خود می‌رسد اعمال می‌شود). به‌عنوان مثال، <code>0.5</code> نشان‌دهنده کاهش کیفیت به ۵۰٪ از مقدار اصلی است.</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">حداکثر مقدار مقیاس. معمولاً برابر با <code>1.0</code> (کیفیت ۱۰۰٪) است، این پیش‌فرض سطح ۰ (Level 0) است.</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">تأثیر بصری در رندرینگ (<code>Low</code>، <code>Medium</code>، <code>High</code>). افزونه به‌طور سیستماتیک افزایش سطح (کاهش کیفیت) برای Scalerهای با تأثیر بصری <code>Low</code> را در اولویت قرار می‌دهد.</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">مشخص می‌کند که Scaler کدام زیرسیستم را بهینه‌سازی می‌کند (<code>CPU</code>، <code>GPU</code> یا هر دو). اگر گلوگاه (Bottleneck) فعلی سیستم <code>CPU</code> باشد، افزونه Scalerهای متمرکز بر <code>GPU</code> را نادیده می‌گیرد.</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">برخی Scalerهای اختصاصی (<code>WebResolutionScaler</code>، <code>WebCameraClipScaler</code>، <code>WebLayerCullingScaler</code>) تنظیمات خود را به‌جای اعمال سراسری، روی دوربین‌های خاصی در صحنه اعمال می‌کنند.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">کار با تگ‌های دوربین (Camera Tags)</p><p>این Scalerها از فراخوانی <code>Camera.main</code> استفاده نمی‌کنند. در عوض، آنها دوربین‌های فعال را با استفاده از آرایه <code>Target Tags</code> اسکن می‌کنند.</p><p>به‌طور پیش‌فرض، تگ <code>MainCamera</code> در آنجا مشخص شده است. <strong>اگر بازی شما از تگ‌های دوربین سفارشی (مانند <code>PlayerCamera</code>) استفاده می‌کند، باید آنها را در تنظیمات Scaler اضافه کنید.</strong> در غیر این صورت مقیاس‌بندی روی آن دوربین‌ها فعال نمی‌شود.</p></div><h2 id="تنظیمات-توسعه-development-settings" tabindex="-1">تنظیمات توسعه (Development Settings) <a class="header-anchor" href="#تنظیمات-توسعه-development-settings" aria-label="Permalink to &quot;تنظیمات توسعه (Development Settings)&quot;">​</a></h2><p>این بخش به دیباگ کردن رفتار افزونه در مرورگر یا ادیتور (Editor) اختصاص دارد.</p><table tabindex="0"><thead><tr><th style="text-align:left;">پارامتر</th><th style="text-align:left;">توضیحات</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">به شما اجازه می‌دهد تا گزارش (Log) دقیقی از عملکردهای افزونه را در کنسول مرورگر (یا Unity) ثبت کنید. این گزینه پیام‌هایی در مورد تغییرات Bottleneck، فعال‌سازی Scalerها و راه‌اندازی سیستم جریمه ضد یویو چاپ می‌کند.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">بهینه‌سازی</p><p>ثبت وقایع (Logging) از کپسول‌های داخلی <code>DebugWebAP</code> استفاده می‌کند. به‌شدت توصیه می‌شود گزینه <code>Logging</code> را در نسخه‌های نهایی (Release Build) غیرفعال کنید تا منابع حفظ شده و کنسول تمیز بماند.</p></div></div>',1)])])}const p=a(r,[["render",n]]);export{x as __pageData,p as default};
